import React, { useState, useEffect } from 'react';
import { Link as RouterLink } from 'react-router-dom';
import {
  Box,
  Button,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Stack,
  Paper,
  useTheme,
  Avatar,
  Chip,
  Fade,
  Divider,
  IconButton
} from '@mui/material';
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import StarIcon from '@mui/icons-material/Star';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import PlayArrowIcon from '@mui/icons-material/PlayArrow';

const HomePage = () => {
  const theme = useTheme();
  const [currentExample, setCurrentExample] = useState(0);

  // Dynamic testimonial examples
  const examples = [
    {
      industry: "Life Coaching",
      original: "The coaching was good. I learned some things that helped me.",
      enhanced: "Working with Sarah transformed my approach to challenges. I went from feeling stuck to landing two major clients in just 3 weeks. Her coaching didn't just teach me tactics—it changed my entire mindset about what's possible.",
      client: "Michael T.",
      avatar: "M"
    },
    {
      industry: "Web Design",
      original: "They built a nice website for me. It works well.",
      enhanced: "The team at DesignPro delivered beyond my expectations. My new website has increased conversions by 43% in the first month alone. Their attention to detail and strategic approach to UX completely transformed my online presence.",
      client: "Jessica K.",
      avatar: "J"
    },
    {
      industry: "Fitness Training",
      original: "Good trainer. I lost some weight and feel better.",
      enhanced: "After 3 months with Alex, I've lost 28 pounds and completely transformed my relationship with fitness. His personalized approach addressed my specific challenges, and for the first time in my life, I actually look forward to my workouts!",
      client: "David R.",
      avatar: "D"
    }
  ];

  // Auto-rotate examples
  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentExample((prev) => (prev + 1) % examples.length);
    }, 8000);
    return () => clearInterval(interval);
  }, [examples.length]);

  return (
    <Box sx={{ overflow: 'hidden' }}>
      {/* Hero Section */}
      <Box 
        sx={{
          pt: { xs: 10, md: 16 },
          pb: { xs: 12, md: 18 },
          position: 'relative',
        }}
      >
        {/* Background gradient */}
        <Box 
          sx={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'radial-gradient(circle at 20% 20%, rgba(93, 95, 239, 0.08) 0%, rgba(93, 95, 239, 0) 50%)',
            zIndex: -1
          }}
        />

        {/* Floating shapes */}
        <Box 
          sx={{
            position: 'absolute',
            top: '15%',
            right: '5%',
            width: '300px',
            height: '300px',
            borderRadius: '50%',
            background: 'radial-gradient(circle, rgba(255, 125, 107, 0.1) 0%, rgba(255, 125, 107, 0) 70%)',
            zIndex: -1,
            animation: 'float 8s ease-in-out infinite'
          }}
        />

        <Box 
          sx={{
            position: 'absolute',
            bottom: '10%',
            left: '10%',
            width: '200px',
            height: '200px',
            borderRadius: '50%',
            background: 'radial-gradient(circle, rgba(93, 95, 239, 0.1) 0%, rgba(93, 95, 239, 0) 70%)',
            zIndex: -1,
            animation: 'float 6s ease-in-out infinite alternate'
          }}
        />

        <Container maxWidth="lg">
          <Grid container spacing={4} alignItems="center">
            <Grid item xs={12} md={6}>
              <Box sx={{ maxWidth: 600, mx: 'auto', textAlign: { xs: 'center', md: 'left' } }}>
                <Chip 
                  label="AI-Powered Testimonials" 
                  color="primary" 
                  size="small"
                  icon={<AutoAwesomeIcon />}
                  sx={{ 
                    mb: 3, 
                    fontWeight: 600,
                    background: theme.palette.primary.light,
                    color: theme.palette.primary.dark,
                    '& .MuiChip-icon': { color: theme.palette.primary.dark }
                  }} 
                />

                <Typography 
                  variant="h1" 
                  gutterBottom
                  sx={{ 
                    fontSize: { xs: '2.5rem', md: '3.5rem' },
                    mb: 2
                  }}
                >
                  Turn <Box component="span" sx={{ color: 'primary.main' }}>"It was good"</Box> into testimonials that sell
                </Typography>

                <Typography 
                  variant="subtitle1" 
                  color="text.secondary" 
                  sx={{ 
                    mb: 4,
                    fontSize: { xs: '1rem', md: '1.25rem' },
                    fontWeight: 400
                  }}
                >
                  Enhance bland client feedback into compelling stories that showcase your true impact—with AI that captures transformation, emotion, and results.
                </Typography>

                <Stack 
                  direction={{ xs: 'column', sm: 'row' }} 
                  spacing={2}
                  sx={{ 
                    justifyContent: { xs: 'center', md: 'flex-start' },
                    mb: 4
                  }}
                >
                  <Button 
                    variant="contained" 
                    color="primary" 
                    size="large"
                    component={RouterLink}
                    to="/enhance"
                    endIcon={<ArrowForwardIcon />}
                    sx={{ 
                      py: 1.5,
                      px: 3,
                      fontSize: '1rem'
                    }}
                  >
                    Enhance a Testimonial
                  </Button>

                  <Button 
                    variant="outlined" 
                    color="primary"
                    size="large"
                    startIcon={<PlayArrowIcon />}
                    sx={{ py: 1.5, px: 3 }}
                  >
                    See How It Works
                  </Button>
                </Stack>

                <Box 
                  sx={{ 
                    display: 'flex', 
                    alignItems: 'center', 
                    gap: 1.5,
                    justifyContent: { xs: 'center', md: 'flex-start' }
                  }}
                >
                  <Box sx={{ display: 'flex' }}>
                    {[...Array(5)].map((_, i) => (
                      <StarIcon key={i} sx={{ color: '#FFCA28', fontSize: 20 }} />
                    ))}
                  </Box>
                  <Typography variant="body2" color="text.secondary">
                    <strong>4.9/5</strong> from 200+ users
                  </Typography>
                </Box>
              </Box>
            </Grid>

            <Grid item xs={12} md={6}>
              <Box 
                sx={{ 
                  position: 'relative',
                  height: { xs: 400, md: 480 },
                  mx: 'auto',
                  maxWidth: 560
                }}
              >
                {examples.map((example, index) => (
                  <Fade 
                    key={index} 
                    in={currentExample === index} 
                    timeout={800}
                    style={{ 
                      position: 'absolute',
                      top: 0,
                      left: 0,
                      right: 0,
                      display: currentExample === index ? 'block' : 'none'
                    }}
                  >
                    <Box>
                      <Card 
                        elevation={3}
                        sx={{ 
                          mb: 3, 
                          p: 3,
                          borderRadius: 3,
                          border: '1px solid',
                          borderColor: 'grey.200',
                          bgcolor: 'grey.50'
                        }}
                      >
                        <Typography variant="overline" color="text.secondary" sx={{ fontWeight: 600 }}>
                          ORIGINAL TESTIMONIAL
                        </Typography>
                        <Typography variant="body1" sx={{ mt: 1, fontStyle: 'italic', color: 'text.secondary' }}>
                          "{example.original}"
                        </Typography>
                        <Chip 
                          label={example.industry} 
                          size="small" 
                          sx={{ mt: 2, bgcolor: 'grey.100', color: 'text.secondary' }}
                        />
                      </Card>

                      <Card 
                        elevation={3}
                        sx={{ 
                          p: 3,
                          borderRadius: 3,
                          position: 'relative',
                          background: 'linear-gradient(135deg, #F5F7FF 0%, #FAFBFF 100%)',
                          border: '1px solid',
                          borderColor: 'primary.light',
                          boxShadow: '0 10px 30px rgba(93, 95, 239, 0.1)'
                        }}
                      >
                        <Box 
                          sx={{ 
                            position: 'absolute', 
                            top: -12, 
                            left: 24,
                            bgcolor: 'primary.main',
                            color: 'white',
                            px: 2,
                            py: 0.5,
                            borderRadius: 2,
                            fontSize: '0.75rem',
                            fontWeight: 600,
                            display: 'flex',
                            alignItems: 'center',
                            gap: 0.5
                          }}
                        >
                          <AutoAwesomeIcon fontSize="small" />
                          ENHANCED
                        </Box>

                        <Typography variant="body1" sx={{ mt: 2, fontWeight: 500, fontSize: '1.1rem' }}>
                          "{example.enhanced}"
                        </Typography>

                        <Box sx={{ display: 'flex', alignItems: 'center', mt: 3 }}>
                          <Avatar 
                            sx={{ 
                              bgcolor: 'primary.main',
                              width: 36,
                              height: 36,
                              fontSize: '1rem',
                              mr: 1.5
                            }}
                          >
                            {example.avatar}
                          </Avatar>
                          <Box>
                            <Typography variant="subtitle2">
                              {example.client}
                            </Typography>
                            <Typography variant="caption" color="text.secondary">
                              Verified Client
                            </Typography>
                          </Box>
                          <Box sx={{ ml: 'auto' }}>
                            <Chip 
                              icon={<CheckCircleIcon fontSize="small" />}
                              label="Verified" 
                              size="small"
                              sx={{ 
                                bgcolor: 'success.light',
                                color: 'success.main',
                                fontWeight: 600,
                                '& .MuiChip-icon': { color: 'success.main' }
                              }}
                            />
                          </Box>
                        </Box>
                      </Card>
                    </Box>
                  </Fade>
                ))}

                <Box 
                  sx={{ 
                    position: 'absolute',
                    bottom: -20,
                    left: 0,
                    right: 0,
                    display: 'flex',
                    justifyContent: 'center',
                    gap: 1
                  }}
                >
                  {examples.map((_, index) => (
                    <Box 
                      key={index}
                      onClick={() => setCurrentExample(index)}
                      sx={{
                        width: 8,
                        height: 8,
                        borderRadius: '50%',
                        bgcolor: currentExample === index ? 'primary.main' : 'grey.300',
                        cursor: 'pointer',
                        transition: 'all 0.2s'
                      }}
                    />
                  ))}
                </Box>
              </Box>
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* How It Works Section */}
      <Box sx={{ py: 10, bgcolor: 'grey.50' }}>
        <Container maxWidth="lg">
          <Box sx={{ textAlign: 'center', mb: 8 }}>
            <Typography variant="h2" gutterBottom>
              How It Works
            </Typography>
            <Typography variant="subtitle1" color="text.secondary" sx={{ maxWidth: 600, mx: 'auto' }}>
              Transform bland testimonials into powerful stories in three simple steps
            </Typography>
          </Box>

          <Grid container spacing={4}>
            <Grid item xs={12} md={4}>
              <Card 
                sx={{ 
                  height: '100%',
                  p: 4,
                  transition: 'transform 0.3s',
                  '&:hover': {
                    transform: 'translateY(-8px)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 60,
                    height: 60,
                    borderRadius: 2,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    bgcolor: 'primary.light',
                    color: 'primary.dark',
                    mb: 3,
                    fontSize: '1.5rem',
                    fontWeight: 700
                  }}
                >
                  1
                </Box>
                <Typography variant="h5" gutterBottom>
                  Submit raw testimonial
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Paste your client's original words, no matter how brief or bland they might be.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} md={4}>
              <Card 
                sx={{ 
                  height: '100%',
                  p: 4,
                  transition: 'transform 0.3s',
                  '&:hover': {
                    transform: 'translateY(-8px)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 60,
                    height: 60,
                    borderRadius: 2,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    bgcolor: 'primary.light',
                    color: 'primary.dark',
                    mb: 3,
                    fontSize: '1.5rem',
                    fontWeight: 700
                  }}
                >
                  2
                </Box>
                <Typography variant="h5" gutterBottom>
                  Get AI-enhanced version
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Our AI extracts the transformation, emotion, and impact from your client's experience.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} md={4}>
              <Card 
                sx={{ 
                  height: '100%',
                  p: 4,
                  transition: 'transform 0.3s',
                  '&:hover': {
                    transform: 'translateY(-8px)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 60,
                    height: 60,
                    borderRadius: 2,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    bgcolor: 'primary.light',
                    color: 'primary.dark',
                    mb: 3,
                    fontSize: '1.5rem',
                    fontWeight: 700
                  }}
                >
                  3
                </Box>
                <Typography variant="h5" gutterBottom>
                  One-click client approval
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Send a verification link to your client for instant approval with a single click.
                </Typography>
              </Card>
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* CTA Section */}
      <Box sx={{ py: 10 }}>
        <Container maxWidth="md">
          <Card 
            sx={{ 
              p: { xs: 4, md: 6 },
              background: 'linear-gradient(135deg, #5D5FEF 0%, #7879F1 100%)',
              color: 'white',
              textAlign: 'center',
              position: 'relative',
              overflow: 'hidden'
            }}
          >
            <Box 
              sx={{
                position: 'absolute',
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                opacity: 0.1,
                backgroundImage: 'radial-gradient(circle, #ffffff 1px, transparent 1px)',
                backgroundSize: '20px 20px'
              }}
            />

            <Typography variant="h3" gutterBottom>
              Ready to transform your testimonials?
            </Typography>
            <Typography variant="subtitle1" sx={{ mb: 4, opacity: 0.9, maxWidth: 600, mx: 'auto' }}>
              Start free, no credit card required. Upgrade when you need more.
            </Typography>
            <Button 
              variant="contained" 
              size="large"
              component={RouterLink}
              to="/enhance"
              sx={{ 
                px: 4, 
                py: 1.5,
                bgcolor: 'white',
                color: 'primary.main',
                '&:hover': {
                  bgcolor: 'rgba(255, 255, 255, 0.9)'
                }
              }}
            >
              Get Started Now
            </Button>
          </Card>
        </Container>
      </Box>
    </Box>
  );
};

export default HomePage;
